// validateTaskImageMagicNumber 验证图片文件的魔数（文件头）
func validateTaskImageMagicNumber(data []byte, ext string) bool {
	if len(data) < 8 {
		return false
	}

	switch ext {
	case ".png":
		pngMagic := []byte{0x89, 0x50, 0x4E, 0x47, 0x0D, 0x0A, 0x1A, 0x0A}
		return bytes.HasPrefix(data, pngMagic)
	case ".jpg", ".jpeg":
		jpegMagic := []byte{0xFF, 0xD8, 0xFF}
		return bytes.HasPrefix(data, jpegMagic)
	case ".svg":
		content := bytes.TrimLeft(data, "\xef\xbb\xbf")
		contentStr := strings.TrimSpace(string(content[:min(len(content), 1024)]))
		return strings.HasPrefix(contentStr, "<?xml") ||
			strings.HasPrefix(contentStr, "<svg") ||
			strings.HasPrefix(contentStr, "<!DOCTYPE svg")
	default:
		return false
	}
}

// sanitizeTaskFileName 清理文件名，防止路径遍历攻击
func sanitizeTaskFileName(fileName string) string {
	fileName = filepath.Base(fileName)
	reg := regexp.MustCompile(`[^a-zA-Z0-9_\-.]`)
	fileName = reg.ReplaceAllString(fileName, "_")

	if fileName == "" || fileName == "." || fileName == ".." {
		return ""
	}

	if len(fileName) > 100 {
		fileName = fileName[:100]
	}

	return fileName
}

